import { describe, test, expect } from "bun:test";
import {
  PHASE1_AI_GATE,
  passesPhase1Gate,
  WEIGHTS,
  DEFAULT_WEIGHTS,
  computeAlgorithmicScore,
  type ScoringInput,
  type ScanCriteriaForScoring,
} from "~/.claude/skills/Commerce/JobEngine/Tools/lib/scoring.ts";

// =============================================================================
// 1. PHASE1_AI_GATE constant equals 50
// =============================================================================
describe("PHASE1_AI_GATE", () => {
  test("equals 50", () => {
    expect(PHASE1_AI_GATE).toBe(50);
  });
});

// =============================================================================
// 2. passesPhase1Gate(49) returns false
// 3. passesPhase1Gate(50) returns true
// =============================================================================
describe("passesPhase1Gate", () => {
  test("returns false for score 49", () => {
    expect(passesPhase1Gate(49)).toBe(false);
  });

  test("returns true for score 50", () => {
    expect(passesPhase1Gate(50)).toBe(true);
  });
});

// =============================================================================
// 4. WEIGHTS values sum to exactly 100
// =============================================================================
describe("WEIGHTS", () => {
  test("values sum to exactly 100", () => {
    const sum = Object.values(DEFAULT_WEIGHTS).reduce((a, b) => a + b, 0);
    expect(sum).toBe(100);
  });

  test("runtime WEIGHTS also sum to 100 (when no config override)", () => {
    const sum = Object.values(WEIGHTS).reduce((a, b) => a + b, 0);
    expect(sum).toBe(100);
  });
});

// =============================================================================
// 5. computeAlgorithmicScore with perfect-match input produces total >= 80
// =============================================================================
describe("computeAlgorithmicScore", () => {
  test("perfect-match input produces total >= 80", () => {
    const listing: ScoringInput = {
      title: "Senior Machine Learning Engineer",
      company: "Anthropic",
      location: "Remote, USA",
      salary_min_estimate: 200000,
      posting_age_hours: 12,
      description_snippet: "AI and deep learning infrastructure",
    };

    const criteria: ScanCriteriaForScoring = {
      role_queries: ["machine learning engineer"],
      location: {
        cities: ["San Francisco"],
        remote: true,
        hybrid: true,
      },
      salary: {
        min: 150000,
      },
      recency: {
        max_age_days: 7,
      },
      seniority: ["senior"],
      industry_keywords: ["ai", "deep learning"],
    };

    const result = computeAlgorithmicScore(listing, criteria);
    expect(result.total).toBeGreaterThanOrEqual(80);
  });
});
